esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS
    failed_puts = SUM(RATE(ibmmq_qmgr_failed_mqput_total)),
    failed_put1s = SUM(RATE(ibmmq_qmgr_failed_mqput1_total)),
    failed_gets = SUM(RATE(ibmmq_qmgr_failed_mqget_total))
    BY attributes.qmgr
| EVAL total_failed_msg_ops = COALESCE(failed_puts, 0) + COALESCE(failed_put1s, 0) + COALESCE(failed_gets, 0)
// Alert when failed put or get operations are detected
// In a healthy system, these should all be at zero rate
// Failures indicate queue full, auth issues, or application errors
// Adjust threshold based on expected traffic volume
| WHERE total_failed_msg_ops > 0
